from sklearn.preprocessing import normalize
from sklearn.metrics import pairwise_distances
import joblib

app = Flask(__name__)

# Load employee photos and encode faces
def load_employee_photos(directory):
    encodings = []
    names = []
    for filename in os.listdir(directory):
        if filename.endswith(".jpg") or filename.endswith(".png"):
            image = face_recognition.load_image_file(os.path.join(directory, filename))
            encoding = face_recognition.face_encodings(image)
            if encoding:
                encodings.append(encoding[0])
                names.append(filename.split('.')[0])  # Use filename without extension as name
    return np.array(encodings), names

# Load model
encodings, names = load_employee_photos('employee_photos')
model = joblib.load('face_recognition_model.pkl') if os.path.exists('face_recognition_model.pkl') else None

@app.route('/recognize', methods=['POST'])
def recognize_face():
    if 'image' not in request.files:
        return jsonify({'error': 'No image provided'}), 400
    
    image_file = request.files['image']
    image = face_recognition.load_image_file(image_file)
    face_encodings = face_recognition.face_encodings(image)

    if not face_encodings:
        return jsonify({'error': 'No face found in the image'}), 400

    face_encoding = face_encodings[0]
    distances = pairwise_distances([face_encoding], encodings)
    probabilities = np.exp(-distances) / np.sum(np.exp(-distances))

    response = {name: float(prob) for name, prob in zip(names, probabilities[0])}
    return jsonify(response)

